using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly Payments.PaymentGateway _gateway;

    public PaymentGatewayTests()
    {
        _gateway = new Payments.PaymentGateway();
    }

    // ── ChargeAsync ──────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidCardAndAmount_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.ChargeId);
        Assert.IsNotEmpty(result.ChargeId);
    }

    [TestMethod]
    [DataRow("tok_visa", 0.01, DisplayName = "Minimum charge")]
    [DataRow("tok_mastercard", 9999.99, DisplayName = "Large charge")]
    [DataRow("tok_amex", 1.00, DisplayName = "One dollar charge")]
    public async Task ChargeAsync_VariousValidAmounts_Succeeds(string token, double amount)
    {
        var result = await _gateway.ChargeAsync(token, (decimal)amount);

        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            async () => await _gateway.ChargeAsync(null!, 10m));
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_EmptyOrWhitespaceToken_ThrowsArgumentException(string token)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync(token, 10m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-0.01)]
    public async Task ChargeAsync_ZeroOrNegativeAmount_ThrowsArgumentOutOfRangeException(double amount)
    {
        await Assert.ThrowsExactlyAsync<ArgumentOutOfRangeException>(
            async () => await _gateway.ChargeAsync("tok_valid", (decimal)amount));
    }

    [TestMethod]
    public async Task ChargeAsync_TwoCharges_ReturnDistinctChargeIds()
    {
        var result1 = await _gateway.ChargeAsync("tok_visa", 10m);
        var result2 = await _gateway.ChargeAsync("tok_visa", 20m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    // ── RefundAsync ──────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessWithRefundId()
    {
        var charge = await _gateway.ChargeAsync("tok_visa", 50m);

        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsNotNull(refund.RefundId);
        Assert.IsNotEmpty(refund.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            async () => await _gateway.RefundAsync(null!));
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_EmptyOrWhitespaceChargeId_ThrowsArgumentException(string chargeId)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.RefundAsync(chargeId));
    }

    [TestMethod]
    public async Task RefundAsync_NonexistentChargeId_ReturnsFailure()
    {
        var refund = await _gateway.RefundAsync("ch_does_not_exist");

        Assert.IsFalse(refund.Success);
    }

    [TestMethod]
    public async Task RefundAsync_SameChargeRefundedTwice_SecondRefundFails()
    {
        var charge = await _gateway.ChargeAsync("tok_visa", 75m);

        var first = await _gateway.RefundAsync(charge.ChargeId);
        var second = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(first.Success);
        Assert.IsFalse(second.Success);
    }
}

